#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int E[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &E[i]);
        }
        qsort(E, N, sizeof(int), compare);
        int stones[N];
        int totalEnergy = 0;
        for (int i = 0; i < N; i++) {
            stones[i] = M / N;
            if (i < M % N) {
                stones[i]++;
            }
        }
        for (int i = 0; i < N; i++) {
            int k = 0;
            for (int j = 0; j < N; j++) {
                if (stones[j] > stones[i]) {
                    k++;
                }
            }
            totalEnergy += E[i] * k;
        }
        printf("%d\n", totalEnergy);
    }
    return 0;
}

