import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] E = new int[N];
            for (int i = 0; i < N; i++) {
                E[i] = sc.nextInt();
            }
            Arrays.sort(E);
            int[] stones = new int[N];
            int totalEnergy = 0;
            for (int i = 0; i < N; i++) {
                stones[i] = M / N;
                if (i < M % N) {
                    stones[i]++;
                }
            }
            for (int i = 0; i < N; i++) {
                int k = 0;
                for (int j = 0; j < N; j++) {
                    if (stones[j] > stones[i]) {
                        k++;
                    }
                }
                totalEnergy += E[i] * k;
            }
            System.out.println(totalEnergy);
        }
    }
}

